example.js<pre><code>// Create RawMeshBuilder, use method chaining to build vertices
const rawMeshBuilder = new RawMeshBuilder(4, "exterior", Resources.idr("wordmark.png"))
.vertex(0, 0, -2).normal(0, 0, 0).uv(1, 1).endVertex()
.vertex(0, 1, -2).normal(0, 0, 0).uv(1, 0).endVertex()
.vertex(0, 1, 2).normal(0, 0, 0).uv(0, 0).endVertex()
.vertex(0, 0, 2).normal(0, 0, 0).uv(0, 1).endVertex();

const wordmarkRawModel = new RawModel(); // Create an empty RawModel
wordmarkRawModel.append(rawMeshBuilder.getMesh()) // Append the mesh to RawModel
wordmarkRawModel.triangulate();
wordmarkRawModel.generateNormals();

let wordmarkModel = ModelManager.upload(wordmarkRawModel); // Upload the model to GPU

function render(ctx, state, vehicle) {
    for(let carIndex of ctx.getMyCars()) {
        let renderManager = ctx.getCarRenderManager(carIndex);
        renderManager.drawModel(wordmarkModel, null); // Draw the model out
    }
}
</code></pre>

example.js<pre><code>/* Eyecandy code to play a looping music. If anyone right-clicked the block, lower the volume for 5s before raising back up again. */

function create(ctx, state, eyecandy) {
    state.lower_vol_timer = 0;

    state.sound = TickableSoundInstance.create(Resources.id("minecraft:my.music_id"), "MASTER")
        .setPos(eyecandy.pos()) // Initialize position
        .setLoopable(true) // Repeat the music
        .setLoopDelay(80); // Have a 4 seconds (80 ticks) break before looping again
    ctx.getSoundManager().play(state.sound); // Play it
}

function render(ctx, state, eyecandy) {
    // Check if eyecandy is right-clicked
    if(ctx.events().onBlockUse.occurred()) {
        state.lower_vol_timer = 5; // Set lower volume timer to 5s
        ctx.events().handled(); // Acknowledge right-click event
    }

    if(state.lower_vol_timer &gt; 0) { // Timer is not up
        state.lower_vol_timer -= Timing.delta(); // Countdown timer
        state.sound.setSoundVolume(0.25); // Lower our volume to 25%.
    } else {
        state.sound.setSoundVolume(1); // Time is up, set our volume back to 100%.
        state.lower_vol_timer = 0;
    }
}

function dispose(ctx, state, eyecandy) {
    ctx.getSoundManager().stop(state.sound); // IMPORTANT: Stop the sound! Since after this we won't have reference to `state.sound` anymore!
}
</code></pre>

NTE Eyecandy FormatMTR 4 Custom Resources Format <p>When using the NTE Eyecandy format (Individualized json file), put the necessary variables within <code>scriptInput</code>.</p> eyecandy.json<pre><code>{
    "nte_lcd": {
        "name": "NTE LCD Test",
        "scriptFiles": ["mtrsteamloco:eyecandies/js/nte_lcd_test/main.js"],
-       "parameters": {
-           "stDay": "310",
-           "ksDay": "514"
-       }
+       "scriptInput": {
+           "name": "NTE LCD Test",
+           "parameters": {
+              "stDay": "310",
+              "ksDay": "514"
+          }
+       }
    }
}
</code></pre> <p>When using the MTR 4 Custom Resources Format, the corresponding field is <code>input</code> within the script object.</p> mtr_custom_resources.json<pre><code>{
    "objects": [
        {
            "id": "nte_lcd",
            "name": "NTE LCD Test",
            "scriptId": "nte_lcd"
        }
    ],
    "objectScripts": [
        {
            "id": "nte_lcd",
            "scriptLocations": ["mtrsteamloco:eyecandies/js/nte_lcd_test/main.js"],
+           "input": {
+               "name": "NTE LCD Test",
+               "parameters": {
+                  "stDay": "310",
+                  "ksDay": "514"
+               }
+           }
        }
    ]
}
</code></pre> <p>Then rename <code>CONFIG_INFO</code> to <code>SCRIPT_INPUT</code> within the script. script.js<pre><code>- print(CONFIG_INFO.name); // NTE LCD Test
- print(CONFIG_INFO.parameters.stDay) // 310
- print(CONFIG_INFO.parameters.ksDay) // 514
+ print(SCRIPT_INPUT.name); // NTE LCD Test
+ print(SCRIPT_INPUT.parameters.stDay) // 310
+ print(SCRIPT_INPUT.parameters.ksDay) // 514
</code></pre></p>

